using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems(int count = 1) =>
        Enumerable.Range(1, count).Select(i => new OrderItem
        {
            ProductName = $"Product {i}",
            Price = 10.00m * i,
            Quantity = i
        }).ToList();

    #region CreateOrder - Happy Path

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual("customer-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithNonEmptyId()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithAssignedItems()
    {
        // Arrange
        var items = CreateSampleItems(2);

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 25.00m, Quantity = 3 }
        };

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual(75.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_CalculatesTotalAsSumOfLineItems()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10.00m, Quantity = 2 },  // 20
            new() { ProductName = "B", Price = 5.50m, Quantity = 4 }    // 22
        };

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual(42.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidInputs_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateSampleItems();

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} not between {before} and {after}");
    }

    #endregion

    #region CreateOrder - Validation

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("customer-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var emptyItems = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("customer-1", emptyItems));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_WithExistingOrderId_ReturnsMatchingOrder()
    {
        // Arrange
        var created = _sut.CreateOrder("customer-1", CreateSampleItems());

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllCustomerOrders()
    {
        // Arrange
        _sut.CreateOrder("customer-A", CreateSampleItems());
        _sut.CreateOrder("customer-A", CreateSampleItems());
        _sut.CreateOrder("customer-B", CreateSampleItems());

        // Act
        var orders = _sut.GetOrdersByCustomer("customer-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        // Arrange
        _sut.CreateOrder("customer-A", CreateSampleItems());

        // Act
        var orders = _sut.GetOrdersByCustomer("customer-Z");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyOrdersForSpecifiedCustomer()
    {
        // Arrange
        _sut.CreateOrder("customer-A", CreateSampleItems());
        _sut.CreateOrder("customer-B", CreateSampleItems());

        // Act
        var orders = _sut.GetOrdersByCustomer("customer-A");

        // Assert
        foreach (var order in orders)
        {
            Assert.AreEqual("customer-A", order.CustomerId);
        }
    }

    #endregion
}

